import 'package:flutter_fractals/core/models/fractal_parameter.dart';

/// Replayable presentation and update contract for numeric parameter controls.
///
/// The controls sheet receives dynamic `Object` values from controller state.
/// Keeping slider normalization, label formatting, division calculation, and
/// emitted values together prevents the visible label from drifting away from
/// the clamped slider position when stale/replayed values are malformed.
final class NumericParamControlPlan {
  const NumericParamControlPlan._({
    required this.type,
    required this.range,
    required this.value,
    required this.divisions,
    required this.valueLabel,
  });

  factory NumericParamControlPlan.fromParam({
    required FractalParameter param,
    required Object value,
  }) {
    assert(
      param.type == FractalParamType.float ||
          param.type == FractalParamType.integer,
      'NumericParamControlPlan only supports numeric parameter types',
    );

    final range = NumericParamControlRange.fromParam(param);
    final rawValue = _finiteNumericValue(value) ??
        _finiteNumericValue(param.defaultValue) ??
        range.min;
    final sliderValue = range.clamp(rawValue);

    return NumericParamControlPlan._(
      type: param.type,
      range: range,
      value: sliderValue,
      divisions: range.divisionsForStep(param.step),
      valueLabel: _labelFor(
        type: param.type,
        range: range,
        sliderValue: sliderValue,
      ),
    );
  }

  final FractalParamType type;
  final NumericParamControlRange range;

  /// Clamped finite value that is safe to pass to [Slider.value].
  final double value;

  /// Slider divisions, or null when the schema step cannot form divisions.
  final int? divisions;

  /// Label for the same normalized value shown by the slider.
  final String valueLabel;

  double get min => range.min;
  double get max => range.max;

  Object valueForSliderPosition(double sliderPosition) {
    final clamped = range.clamp(sliderPosition);
    return switch (type) {
      FractalParamType.integer => range.integerValueFor(clamped),
      FractalParamType.float => double.parse(clamped.toStringAsFixed(2)),
      FractalParamType.boolean || FractalParamType.enumeration => clamped,
    };
  }

  static String _labelFor({
    required FractalParamType type,
    required NumericParamControlRange range,
    required double sliderValue,
  }) {
    if (type == FractalParamType.integer) {
      return range.integerValueFor(sliderValue).toString();
    }
    return sliderValue.toStringAsFixed(2);
  }

  static double? _finiteNumericValue(Object value) {
    if (value is! num) return null;
    final numericValue = value.toDouble();
    return numericValue.isFinite ? numericValue : null;
  }
}

/// Sanitized numeric range for a parameter slider.
final class NumericParamControlRange {
  const NumericParamControlRange({
    required this.min,
    required this.max,
  });

  factory NumericParamControlRange.fromParam(FractalParameter param) {
    final safeMin = param.min.isFinite ? param.min : 0.0;
    final safeMax = param.max.isFinite ? param.max : safeMin;

    if (safeMin <= safeMax) {
      return NumericParamControlRange(min: safeMin, max: safeMax);
    }
    return NumericParamControlRange(min: safeMax, max: safeMin);
  }

  final double min;
  final double max;

  double get span => max - min;

  double clamp(double value) {
    if (!value.isFinite) return min;
    return value.clamp(min, max).toDouble();
  }

  int? divisionsForStep(double step) {
    if (span <= 0.0 || !step.isFinite || step <= 0.0) return null;

    final rawDivisions = span / step;
    if (!rawDivisions.isFinite) return null;

    final divisions = rawDivisions.round();
    return divisions > 0 ? divisions : null;
  }

  int integerValueFor(double sliderPosition) {
    final rounded = clamp(sliderPosition).round();
    final lower = min.ceil();
    final upper = max.floor();
    if (lower > upper) return rounded;
    return rounded.clamp(lower, upper).toInt();
  }
}

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:provider/provider.dart';
import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/theme/app_theme.dart';
import 'package:flutter_fractals/core/widgets/animated_widgets.dart';
import 'package:flutter_fractals/core/widgets/animation_effects.dart';
import 'package:flutter_fractals/features/controls/param_control_plan.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';
import 'package:flutter_fractals/shared/widgets/app_bottom_sheet.dart';

class FractalControlsSheet extends StatelessWidget {
  const FractalControlsSheet({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    final controller = context.watch<FractalController>();
    final l10n = AppLocalizations.of(context)!;

    return AppBottomSheet(
      maxHeightFactor: 0.38,
      children: [
        AppBottomSheetHeader(
          icon: Icons.tune_rounded,
          title: l10n.controlsTitle,
          subtitle: controller.module.displayName(l10n),
          onClose: () => Navigator.of(context).pop(),
        ),
        const Divider(height: 1, color: AppColors.divider),
        // Scrollable content
        Flexible(
          child: SingleChildScrollView(
            padding: const EdgeInsets.fromLTRB(
              AppSpacing.sm,
              AppSpacing.xs,
              AppSpacing.sm,
              AppSpacing.sm,
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                SectionHeader(title: l10n.controlsTitle),
                ...controller.module.parameters.asMap().entries.map((entry) {
                  return StaggeredItem(
                    index: entry.key,
                    itemDelay: const Duration(milliseconds: 30),
                    child: _ParamControl(
                      param: entry.value,
                      value: controller.params[entry.value.id] ??
                          entry.value.defaultValue,
                      onChanged: (value) =>
                          controller.updateParam(entry.value.id, value),
                    ),
                  );
                }),
                const SizedBox(height: AppSpacing.lg),
                SectionHeader(title: 'Kaleidoscope'),
                const SizedBox(height: AppSpacing.sm),
                _KaleidoscopeControls(),
                const SizedBox(height: AppSpacing.xl),
                SectionHeader(title: l10n.sectionActions),
                const SizedBox(height: AppSpacing.sm),
                Row(
                  children: [
                    Expanded(
                      child: _ActionButton(
                        icon: Icons.restart_alt_rounded,
                        label: l10n.resetView,
                        onPressed: controller.resetView,
                      ),
                    ),
                    const SizedBox(width: AppSpacing.md),
                    Expanded(
                      child: _ActionButton(
                        icon: Icons.settings_backup_restore_rounded,
                        label: l10n.resetParams,
                        onPressed: controller.resetParams,
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: AppSpacing.md),
                SizedBox(
                  width: double.infinity,
                  child: _AnimatedRandomizeButton(
                    label: l10n.randomize,
                    onPressed: () {
                      HapticFeedback.mediumImpact();
                      controller.randomizeParams();
                      // Trigger a small celebration for discovering new fractals
                      controller.recordInterestingSpot();
                    },
                  ),
                ),
                SizedBox(
                    height:
                        MediaQuery.of(context).padding.bottom + AppSpacing.lg),
              ],
            ),
          ),
        ),
      ],
    );
  }
}

class _ActionButton extends StatelessWidget {
  final IconData icon;
  final String label;
  final VoidCallback onPressed;

  const _ActionButton({
    required this.icon,
    required this.label,
    required this.onPressed,
  });

  @override
  Widget build(BuildContext context) {
    return Semantics(
      button: true,
      label: label,
      child: PressableScale(
        onTap: onPressed,
        builder: (isPressed) => AnimatedContainer(
          duration: AppAnimations.fast,
          padding: const EdgeInsets.symmetric(
            horizontal: AppSpacing.xs,
            vertical: AppSpacing.xs,
          ),
          decoration: BoxDecoration(
            color: isPressed
                ? AppColors.primary.withValues(alpha: 0.3)
                : AppColors.border.withValues(alpha: 0.5),
            borderRadius: BorderRadius.circular(AppSpacing.buttonRadius),
          ),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(
                icon,
                size: 16,
                color: isPressed ? AppColors.primary : AppColors.textSecondary,
              ),
              const SizedBox(height: 2),
              Text(
                label,
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
                textAlign: TextAlign.center,
                style: AppTypography.labelSmall.copyWith(
                  color: isPressed ? AppColors.primary : AppColors.textPrimary,
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class _CompactParamSlider extends StatelessWidget {
  final String label;
  final double value;
  final double min;
  final double max;
  final int? divisions;
  final String valueLabel;
  final ValueChanged<double> onChanged;

  const _CompactParamSlider({
    required this.label,
    required this.value,
    required this.min,
    required this.max,
    required this.divisions,
    required this.valueLabel,
    required this.onChanged,
  });

  @override
  Widget build(BuildContext context) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          mainAxisAlignment: MainAxisAlignment.spaceBetween,
          children: [
            Expanded(
              child: Text(
                label,
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
                style: AppTypography.bodySmall.copyWith(
                  color: AppColors.textSecondary,
                ),
              ),
            ),
            const SizedBox(width: AppSpacing.sm),
            Text(
              valueLabel,
              style: AppTypography.labelSmall.copyWith(
                color: AppColors.primary,
                fontWeight: FontWeight.w700,
              ),
            ),
          ],
        ),
        SliderTheme(
          data: SliderTheme.of(context).copyWith(
            trackHeight: 3,
            thumbShape: const RoundSliderThumbShape(enabledThumbRadius: 8),
            overlayShape: const RoundSliderOverlayShape(overlayRadius: 14),
            activeTrackColor: AppColors.primary,
            inactiveTrackColor: AppColors.surfaceVariant,
            thumbColor: Colors.white,
          ),
          child: Semantics(
            label: label,
            value: valueLabel,
            hint: AppLocalizations.of(context)!.semanticSliderAdjust(min, max),
            slider: true,
            child: Slider(
              value: value,
              min: min,
              max: max,
              divisions: divisions,
              onChanged: onChanged,
            ),
          ),
        ),
      ],
    );
  }
}

class _ParamControl extends StatelessWidget {
  final FractalParameter param;
  final Object value;
  final ValueChanged<Object> onChanged;

  const _ParamControl({
    required this.param,
    required this.value,
    required this.onChanged,
  });

  @override
  Widget build(BuildContext context) {
    final l10n = AppLocalizations.of(context)!;

    switch (param.type) {
      case FractalParamType.float:
      case FractalParamType.integer:
        final plan = NumericParamControlPlan.fromParam(
          param: param,
          value: value,
        );

        return Padding(
          padding: const EdgeInsets.only(bottom: AppSpacing.md),
          child: _CompactParamSlider(
            label: param.label(l10n),
            value: plan.value,
            min: plan.min,
            max: plan.max,
            divisions: plan.divisions,
            valueLabel: plan.valueLabel,
            onChanged: (newValue) =>
                onChanged(plan.valueForSliderPosition(newValue)),
          ),
        );

      case FractalParamType.enumeration:
        // Use horizontal scroll for large option sets (e.g. 64 palettes).
        final useScroll = param.options.length > 8;
        return Padding(
          padding: const EdgeInsets.only(bottom: AppSpacing.lg),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                param.label(l10n),
                style: AppTypography.bodyMedium.copyWith(
                  color: AppColors.textPrimary,
                ),
              ),
              const SizedBox(height: AppSpacing.sm),
              if (useScroll)
                SizedBox(
                  height: 40,
                  child: ListView.separated(
                    scrollDirection: Axis.horizontal,
                    itemCount: param.options.length,
                    separatorBuilder: (_, __) =>
                        const SizedBox(width: AppSpacing.sm),
                    itemBuilder: (context, index) {
                      final option = param.options[index];
                      final selected = option.value == value;
                      return _OptionChip(
                        label: option.label(l10n),
                        selected: selected,
                        onSelected: () => onChanged(option.value),
                      );
                    },
                  ),
                )
              else
                Wrap(
                  spacing: AppSpacing.sm,
                  runSpacing: AppSpacing.sm,
                  children: param.options.map((option) {
                    final selected = option.value == value;
                    return _OptionChip(
                      label: option.label(l10n),
                      selected: selected,
                      onSelected: () => onChanged(option.value),
                    );
                  }).toList(),
                ),
            ],
          ),
        );

      case FractalParamType.boolean:
        return Padding(
          padding: const EdgeInsets.only(bottom: AppSpacing.md),
          child: _PremiumSwitch(
            label: param.label(l10n),
            value: value == true,
            onChanged: (newValue) => onChanged(newValue),
          ),
        );
    }
  }
}

class _KaleidoscopeControls extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final controller = context.watch<FractalController>();

    return Column(
      children: [
        Row(
          children: [
