  });

  @override
  State<_AnimatedRandomizeButton> createState() =>
      _AnimatedRandomizeButtonState();
}

class _AnimatedRandomizeButtonState extends State<_AnimatedRandomizeButton>
    with TickerProviderStateMixin {
  late AnimationController _scaleController;
  late AnimationController _shakeController;
  late AnimationController _glowController;
  late Animation<double> _scaleAnimation;
  late Animation<double> _shakeAnimation;
  late Animation<double> _glowAnimation;
  bool _isPressed = false;
  bool _showSparkle = false;

  @override
  void initState() {
    super.initState();

    _scaleController = AnimationController(
      duration: AppAnimations.fast,
      vsync: this,
    );
    _scaleAnimation = Tween<double>(begin: 1.0, end: 0.95).animate(
      CurvedAnimation(
          parent: _scaleController, curve: AppAnimations.snappyCurve),
    );

    _shakeController = AnimationController(
      duration: const Duration(milliseconds: 500),
      vsync: this,
    );
    _shakeAnimation = TweenSequence<double>([
      TweenSequenceItem(tween: Tween(begin: 0.0, end: -0.03), weight: 1),
      TweenSequenceItem(tween: Tween(begin: -0.03, end: 0.03), weight: 2),
      TweenSequenceItem(tween: Tween(begin: 0.03, end: -0.02), weight: 2),
      TweenSequenceItem(tween: Tween(begin: -0.02, end: 0.01), weight: 2),
      TweenSequenceItem(tween: Tween(begin: 0.01, end: 0.0), weight: 1),
    ]).animate(CurvedAnimation(
      parent: _shakeController,
      curve: Curves.easeOut,
    ));

    _glowController = AnimationController(
      duration: const Duration(milliseconds: 600),
      vsync: this,
    );
    _glowAnimation = TweenSequence<double>([
      TweenSequenceItem(tween: Tween(begin: 0.0, end: 1.0), weight: 1),
      TweenSequenceItem(tween: Tween(begin: 1.0, end: 0.0), weight: 2),
    ]).animate(CurvedAnimation(
      parent: _glowController,
      curve: Curves.easeOut,
    ));
  }

  @override
  void dispose() {
    _scaleController.dispose();
    _shakeController.dispose();
    _glowController.dispose();
    super.dispose();
  }

  void _handleTap() {
    widget.onPressed();

    // Trigger animations
    _shakeController.forward(from: 0);
    _glowController.forward(from: 0);

    setState(() => _showSparkle = true);
    Future.delayed(const Duration(milliseconds: 1500), () {
      if (mounted) {
        setState(() => _showSparkle = false);
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    final l10n = AppLocalizations.of(context)!;
    return Semantics(
      button: true,
      label: l10n.semanticRandomizeButton,
      child: SparkleEffect(
        isActive: _showSparkle,
        sparkleCount: 8,
        child: GestureDetector(
          onTapDown: (_) {
            setState(() => _isPressed = true);
            _scaleController.forward();
          },
          onTapUp: (_) {
            setState(() => _isPressed = false);
            _scaleController.reverse();
          },
          onTapCancel: () {
            setState(() => _isPressed = false);
            _scaleController.reverse();
          },
          onTap: _handleTap,
          child: AnimatedBuilder(
            animation: Listenable.merge(
                [_scaleAnimation, _shakeAnimation, _glowAnimation]),
            builder: (context, child) {
              return Transform.scale(
                scale: _scaleAnimation.value,
                child: Transform.rotate(
                  angle: _shakeAnimation.value,
                  child: Stack(
                    children: [
                      // Glow effect
                      if (_glowAnimation.value > 0)
                        Positioned.fill(
                          child: Container(
                            decoration: BoxDecoration(
                              borderRadius: BorderRadius.circular(
                                  AppSpacing.buttonRadius),
                              boxShadow: [
                                BoxShadow(
                                  color: AppColors.primary.withValues(
                                      alpha: _glowAnimation.value * 0.5),
                                  blurRadius: 20,
                                  spreadRadius: 2,
                                ),
                                BoxShadow(
                                  color: AppColors.secondary.withValues(
                                      alpha: _glowAnimation.value * 0.3),
                                  blurRadius: 30,
                                  spreadRadius: 5,
                                ),
                              ],
                            ),
                          ),
                        ),
                      // Button
                      Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: AppSpacing.xxl,
                          vertical: AppSpacing.md + 2,
                        ),
                        decoration: BoxDecoration(
                          gradient: AppColors.primaryGradient,
                          borderRadius:
                              BorderRadius.circular(AppSpacing.buttonRadius),
                          boxShadow: [
                            BoxShadow(
                              color: AppColors.primary
                                  .withValues(alpha: _isPressed ? 0.5 : 0.3),
                              blurRadius: _isPressed ? 16 : 12,
                              offset: const Offset(0, 4),
                            ),
                          ],
                        ),
                        child: Row(
                          mainAxisAlignment: MainAxisAlignment.center,
                          children: [
                            AnimatedRotation(
                              turns: _shakeController.isAnimating ? 0.5 : 0,
                              duration: const Duration(milliseconds: 300),
                              child: const Icon(
                                Icons.shuffle_rounded,
                                size: 20,
                                color: Colors.white,
                              ),
                            ),
                            const SizedBox(width: AppSpacing.sm),
                            Text(
                              widget.label,
                              style: AppTypography.labelLarge.copyWith(
                                color: Colors.white,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
              );
            },
          ),
        ),
      ),
    );
  }
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/controls/param_control_plan.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1,
  double max = 10,
  double step = 1,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: step,
    defaultValue: defaultValue,
  );
}

void main() {
  group('NumericParamControlPlan', () {
    test('uses the clamped slider value for integer labels and updates', () {
      final plan = NumericParamControlPlan.fromParam(
        param: _numericParam(
          type: FractalParamType.integer,
          defaultValue: 5,
          min: 1,
          max: 10,
        ),
        value: 99,
      );

      expect(plan.value, 10);
      expect(plan.valueLabel, '10');
      expect(plan.valueForSliderPosition(99), 10);
    });

    test('falls back to numeric defaults for non-finite values', () {
      final plan = NumericParamControlPlan.fromParam(
        param: _numericParam(
          type: FractalParamType.float,
          defaultValue: 4.25,
          min: 1,
          max: 10,
          step: 0.25,
        ),
        value: double.nan,
      );

      expect(plan.value, 4.25);
      expect(plan.valueLabel, '4.25');
    });

    test('does not derive slider divisions from malformed steps', () {
      for (final step in [0.0, -1.0, double.nan, double.infinity]) {
        final plan = NumericParamControlPlan.fromParam(
          param: _numericParam(
            type: FractalParamType.float,
            defaultValue: 5.0,
            step: step,
          ),
          value: 5.0,
        );

        expect(plan.divisions, isNull, reason: 'step=$step');
      }
    });

    test('integer emissions honor fractional numeric bounds', () {
      final plan = NumericParamControlPlan.fromParam(
        param: _numericParam(
          type: FractalParamType.integer,
          defaultValue: 4,
          min: 1.2,
          max: 10.8,
        ),
        value: 1.2,
      );

      expect(plan.valueLabel, '2');
      expect(plan.valueForSliderPosition(1.2), 2);
      expect(plan.valueForSliderPosition(10.8), 10);
    });
  });

  group('NumericParamControlRange', () {
    test('sanitizes reversed and non-finite schema bounds for replay', () {
      final reversed = NumericParamControlRange.fromParam(
        _numericParam(
          type: FractalParamType.float,
          defaultValue: 5.0,
          min: 10,
          max: 1,
        ),
      );
      final nonFinite = NumericParamControlRange.fromParam(
        _numericParam(
          type: FractalParamType.float,
          defaultValue: 5.0,
          min: double.nan,
          max: double.infinity,
        ),
      );

      expect(reversed.min, 1);
      expect(reversed.max, 10);
      expect(nonFinite.min, 0);
      expect(nonFinite.max, 0);
    });
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// A function that returns a localized string for the current locale.
///
/// Used for parameter labels and option descriptions.
typedef LocalizedText = String Function(AppLocalizations l10n);

/// The data type of a fractal parameter.
///
/// Determines how the parameter is rendered in the UI and how its
/// value is validated and stored.
enum FractalParamType {
  /// A floating-point number parameter.
  ///
  /// Rendered as a slider with continuous values.
  /// Value type: [double]
  float,

  /// An integer parameter.
  ///
  /// Rendered as a slider with discrete steps.
  /// Value type: [int]
  integer,

  /// A selection from a fixed set of options.
  ///
  /// Rendered as a dropdown or segmented control.
  /// Value type: depends on [FractalParamOption.value]
  enumeration,

  /// A boolean on/off parameter.
  ///
  /// Rendered as a switch or checkbox.
  /// Value type: [bool]
  boolean,
}

/// An option for an enumeration-type parameter.
///
/// Defines a single selectable value with its display label.
///
/// Example:
/// ```dart
/// FractalParamOption(
///   value: 0,
///   label: (l10n) => l10n.colorFire,
/// )
/// ```
class FractalParamOption {
  /// The underlying value for this option.
  ///
  /// This is what gets stored in the parameter map and passed to shaders.
  final Object value;

  /// Returns the localized display label for this option.
  final LocalizedText label;

  /// Creates a new parameter option.
  const FractalParamOption({
    required this.value,
    required this.label,
  });
}

/// Defines the schema for a configurable fractal parameter.
///
/// A [FractalParameter] describes how a single adjustable value should
/// behave: its valid range, step increment, default value, and UI
/// representation.
///
/// Parameters are defined per [FractalModule] and used to:
/// - Generate the controls UI automatically
/// - Validate user input
/// - Clamp values to valid ranges
/// - Store and restore presets
///
/// {@category Models}
///
/// Example:
/// ```dart
/// FractalParameter(
///   id: 'iterations',
///   label: (l10n) => l10n.paramIterations,
///   type: FractalParamType.integer,
///   min: 10,
///   max: 500,
///   step: 1,
///   defaultValue: 100,
/// )
/// ```
@immutable
class FractalParameter {
  /// Unique identifier for this parameter.
  ///
  /// Used as the key in parameter maps and for preset serialization.
  /// Should be a lowercase, camelCase string (e.g., 'iterations', 'colorScheme').
  final String id;

  /// Returns the localized display label for this parameter.
  ///
  /// Shown in the controls UI next to the input widget.
  final LocalizedText label;

  /// The data type of this parameter.
  ///
  /// Determines the UI widget and value handling.
  final FractalParamType type;

  /// The minimum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration] and [FractalParamType.boolean],
  /// this is typically 0.
  final double min;

  /// The maximum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration], this should match `options.length - 1`.
  final double max;

  /// The step increment for slider-based inputs.
  ///
  /// For integers, use 1.0. For floats, use an appropriate precision
  /// (e.g., 0.1 or 0.01).
  final double step;

  /// The initial value when no preset is applied.
  ///
  /// Must be within the [min]/[max] range and compatible with [type].
  final Object defaultValue;

  /// Available options for enumeration-type parameters.
  ///
  /// Only used when [type] is [FractalParamType.enumeration].
  /// Empty for other types.
  final List<FractalParamOption> options;

  /// Creates a new [FractalParameter] with the specified schema.
  ///
  /// For enumeration types, ensure [options] is populated with
  /// all valid choices.
  const FractalParameter({
    required this.id,
    required this.label,
    required this.type,
    required this.min,
    required this.max,
    required this.step,
    required this.defaultValue,
    this.options = const [],
  });
}

